new:
void _filterFoods() {
  setState(() {
    if (_filterType == 'اخیر') {
      var entries = _recentEntries;
      if (_searchQuery.isNotEmpty) {
        final q = _searchQuery.toLowerCase();
        final scored = <MealQuickLogEntry, int>{};
        for (final entry in entries) {
          final food = _foodForId(entry.foodId);
          if (food == null) continue;
          final score = _searchScore(food, q);
          if (score > 0) scored[entry] = score;
        }
        entries = scored.keys.toList()
          ..sort((a, b) {
            final byScore = scored[b]!.compareTo(scored[a]!);
            if (byScore != 0) return byScore;
            return b.lastUsed.compareTo(a.lastUsed);
          });
      }
      _filteredRecentEntries = entries;
      return;
    }

    var filtered = List<Food>.from(widget.foods);

    if (_selectedGroup != null && _selectedGroup!.isNotEmpty) {
      filtered =
          filtered.where((f) => f.meta.foodGroup == _selectedGroup).toList();
    }

    if (_filterType == 'مورد علاقه') {
      filtered =
          filtered.where((f) => _favoriteFoodIds.contains(f.id)).toList();
    }

    if (_searchQuery.isNotEmpty) {
      final q = _searchQuery.toLowerCase();
      final scored = <Food, int>{};
      for (final food in filtered) {
        final score = _searchScore(food, q);
        if (score > 0) scored[food] = score;
      }
      filtered = scored.keys.toList()
        ..sort((a, b) {
          final byScore = scored[b]!.compareTo(scored[a]!);
          if (byScore != 0) return byScore;
          return a.displayTitle.compareTo(b.displayTitle);
        });
    } else {
      filtered.sort(
        (a, b) => a.displayTitle
            .toLowerCase()
            .compareTo(b.displayTitle.toLowerCase()),
      );
    }

    _filteredFoods = filtered;
  });
}

