Widget _buildFoodListBody(bool isDark) {
  if (_filterType == 'اخیر') {
    return _buildRecentList(isDark);
  }
  if (_filteredFoods.isEmpty) {
    return _buildEmptyState(isDark);
  }
  return ListView.separated(
    padding: EdgeInsets.fromLTRB(14.w, 6.h, 14.w, 16.h),
    keyboardDismissBehavior: ScrollViewKeyboardDismissBehavior.onDrag,
    cacheExtent: 280,
    itemCount: _filteredFoods.length,
    separatorBuilder: (_, __) => SizedBox(height: 10.h),
    itemBuilder: (context, index) {
      final food = _filteredFoods[index];
      return FoodListCard(
        key: ValueKey<int>(food.id),
        food: food,
        onTap: () => _showAmountDialog(food),
        onFavoriteToggle: () => _toggleFavorite(food),
        onLikeToggle: () => _foodService.toggleLike(food.id),
      );
    },
  );
}

Widget _buildRecentList(bool isDark) {
  if (_filteredRecentEntries.isEmpty) {
    return _buildRecentEmptyState(isDark);
  }
  return ListView.separated(
    padding: EdgeInsets.fromLTRB(14.w, 6.h, 14.w, 16.h),
    keyboardDismissBehavior: ScrollViewKeyboardDismissBehavior.onDrag,
    itemCount: _filteredRecentEntries.length,
    separatorBuilder: (_, __) => SizedBox(height: 8.h),
    itemBuilder: (context, index) {
      final entry = _filteredRecentEntries[index];
      final food = _foodForId(entry.foodId);
      if (food == null) return const SizedBox.shrink();
      return _buildRecentFoodItem(
        food: food,
        entry: entry,
        isDark: isDark,
        key: ValueKey('recent_${entry.foodId}_$index'),
      );
    },
  );
}

