    final isDark = Theme.of(context).brightness == Brightness.dark;
    final accent = color ?? AppTheme.goldColor;

    return Material(
      color: selected
          ? accent.withValues(alpha: isDark ? 0.14 : 0.12)
          : context.cardColor,
      borderRadius: BorderRadius.circular(20.r),
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(20.r),
        child: Container(
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(20.r),
            border: Border.all(
              color: selected
