      // Update filtered foods (they reference the same objects)
      _filteredFoods = widget.foods;
    });
    _filterFoods();
  } catch (e) {
    // Error handled silently
    // Fallback to existing isFavorite values
    setState(() {
      _favoriteFoodIds = widget.foods
          .where((f) => f.isFavorite)
          .map((f) => f.id)
          .toSet();
    });
    _filterFoods();
  }
