Future<void> _syncFavoritesFromDatabase() async {
  try {
    final foodIds = widget.foods.map((f) => f.id).toList();
    final preferences = await _preferencesService.getFoodPreferences(foodIds);
    final favoriteIds = Set<int>.from(preferences['favorites'] as List);

    if (!mounted) return;
    setState(() {
      for (final food in widget.foods) {
        food.isFavorite = favoriteIds.contains(food.id);
      }
      _favoriteFoodIds = favoriteIds;
    });
    if (_filterType == 'مورد علاقه') {
      _filterFoods();
    }
  } catch (e) {
    if (!mounted) return;
    setState(() {
      _favoriteFoodIds = widget.foods
          .where((f) => f.isFavorite)
          .map((f) => f.id)
          .toSet();
    });
    if (_filterType == 'مورد علاقه') {
      _filterFoods();
    }
  }
}

void _filterFoods({String? query}) {
  setState(() {
    if (query != null) {
      _searchQuery = query;
    }

    if (_filterType == 'اخیر') {
      var entries = _recentEntries;
      if (_searchQuery.isNotEmpty) {
        final q = _searchQuery.toLowerCase();
        final scored = <MealQuickLogEntry, int>{};
        for (final entry in entries) {
          final food = _foodForId(entry.foodId);
          if (food == null) continue;
          final score = _searchScore(food, q);
          if (score > 0) scored[entry] = score;
        }
        entries = scored.keys.toList()
          ..sort((a, b) {
            final byScore = scored[b]!.compareTo(scored[a]!);
            if (byScore != 0) return byScore;
            return b.lastUsed.compareTo(a.lastUsed);
          });
      }
      _filteredRecentEntries = entries;
      return;
    }

    if (_filterType == 'همه' && _searchQuery.length < _minSearchChars) {
      _filteredFoods = const [];
      return;
    }

    Iterable<Food> source = widget.foods;
    if (_filterType == 'مورد علاقه') {
      source = source.where((f) => _favoriteFoodIds.contains(f.id));
    }

    if (_searchQuery.isNotEmpty) {
      final q = _searchQuery.toLowerCase();
      final scored = <Food, int>{};
      for (final food in source) {
        final score = _searchScore(food, q);
        if (score > 0) scored[food] = score;
      }
      var filtered = scored.keys.toList()
        ..sort((a, b) {
          final byScore = scored[b]!.compareTo(scored[a]!);
          if (byScore != 0) return byScore;
          return a.displayTitle.compareTo(b.displayTitle);
        });
      if (filtered.length > _maxSearchResults) {
        filtered = filtered.sublist(0, _maxSearchResults);
      }
      _filteredFoods = filtered;
      return;
    }

    var filtered = source.toList()
      ..sort(
        (a, b) => a.displayTitle
            .toLowerCase()
            .compareTo(b.displayTitle.toLowerCase()),
      );
    if (filtered.length > _maxSearchResults) {
      filtered = filtered.sublist(0, _maxSearchResults);
    }
    _filteredFoods = filtered;
  });
}

