class _AddFoodMacroPanel extends StatelessWidget {
  const _AddFoodMacroPanel({
    required this.nutrition,
    required this.basisLabel,
    this.compact = false,
  });

  final FoodNutrition nutrition;
  final String basisLabel;
  final bool compact;

  static double _parse(String raw) =>
      double.tryParse(raw.trim().replaceAll(',', '.')) ?? 0;

  static int _flex(double part, double total) {
    if (total <= 0) return 1;
    return ((part / total) * 100).round().clamp(1, 100);
  }

  static String _formatGram(String raw) {
    final n = double.tryParse(raw.trim().replaceAll(',', '.'));
    if (n == null) return raw;
    if (n % 1 == 0) return n.toInt().toString();
    return n.toStringAsFixed(1);
  }

  @override
  Widget build(BuildContext context) {
    final isDark = Theme.of(context).brightness == Brightness.dark;
    final protein = _parse(nutrition.protein);
    final carbs = _parse(nutrition.carbohydrates);
    final fat = _parse(nutrition.fat);
    final total = protein + carbs + fat;
    final panelBg = isDark
        ? AppTheme.veryDarkBackground.withValues(alpha: 0.55)
        : context.textSecondary.withValues(alpha: 0.05);

    return DecoratedBox(
      decoration: BoxDecoration(
        color: panelBg,
        borderRadius: BorderRadius.circular(compact ? 10.r : 12.r),
        border: Border.all(
          color: context.textSecondary.withValues(alpha: isDark ? 0.14 : 0.1),
        ),
      ),
      child: Padding(
        padding: EdgeInsets.all(compact ? 7.w : 9.w),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            if (total > 0) ...[
              ClipRRect(
                borderRadius: BorderRadius.circular(99.r),
                child: SizedBox(
                  height: compact ? 4.h : 5.h,
                  child: Row(
                    children: [
                      Expanded(
                        flex: _flex(protein, total),
                        child: ColoredBox(color: AppTheme.proteinColor),
                      ),
                      Expanded(
                        flex: _flex(carbs, total),
                        child: ColoredBox(color: AppTheme.carbsColor),
                      ),
                      Expanded(
                        flex: _flex(fat, total),
                        child: ColoredBox(color: AppTheme.fatColor),
                      ),
                    ],
                  ),
                ),
              ),
              SizedBox(height: compact ? 7.h : 9.h),
            ],
            Row(
              textDirection: TextDirection.rtl,
              children: [
                Expanded(
                  child: _AddFoodMacroCell(
                    title: 'پروتئین',
                    value: _formatGram(nutrition.protein),
                    unit: 'گرم',
                    color: AppTheme.proteinColor,
                    compact: compact,
                  ),
                ),
                SizedBox(width: compact ? 5.w : 6.w),
                Expanded(
                  child: _AddFoodMacroCell(
                    title: 'کربوهیدرات',
                    value: _formatGram(nutrition.carbohydrates),
                    unit: 'گرم',
                    color: AppTheme.carbsColor,
                    compact: compact,
                  ),
                ),
                SizedBox(width: compact ? 5.w : 6.w),
                Expanded(
                  child: _AddFoodMacroCell(
                    title: 'چربی',
                    value: _formatGram(nutrition.fat),
                    unit: 'گرم',
                    color: AppTheme.fatColor,
                    compact: compact,
                  ),
                ),
              ],
            ),
            if (basisLabel.trim().isNotEmpty) ...[
              SizedBox(height: compact ? 6.h : 7.h),
              Row(
                textDirection: TextDirection.rtl,
                children: [
                  Icon(
                    LucideIcons.scale,
                    size: compact ? 10.sp : 11.sp,
                    color: context.textSecondary.withValues(alpha: 0.65),
                  ),
                  SizedBox(width: 4.w),
                  Expanded(
                    child: Text(
                      basisLabel,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: TextStyle(
                        fontFamily: AppTheme.fontFamily,
                        color: context.textSecondary.withValues(alpha: 0.85),
                        fontSize: compact ? 9.sp : 9.5.sp,
                        fontWeight: FontWeight.w500,
                      ),
                    ),
                  ),
                ],
              ),
            ],
          ],
        ),
      ),
    );
  }
}

