String _scaledPreviewLine(double amount) {
  final calories = FoodAmountUtils.scaledCalories(
    widget.food,
    amount,
    _selectedUnit,
  ).round();
  final grams = FoodAmountUtils.gramsFromAmount(
    widget.food,
    amount,
    _selectedUnit,
  );
  final gramsLabel = grams > 0 ? '  ·  ≈ ${grams.round()} گرم' : '';
  return '≈ $calories کالری$gramsLabel';
}

