Widget _buildProgressBar(
  double progress,
  bool isOverReference,
  bool isDark,
) {
  final barColor = isOverReference
      ? _statusErrorColor(isDark)
      : (isDark ? AppTheme.goldColor : AppTheme.darkGold);

  return LayoutBuilder(
    builder: (context, constraints) {
      final barWidth = constraints.maxWidth;
      final clampedProgress = progress.clamp(0.0, 1.0);
      final progressWidth = barWidth * clampedProgress;
      const barHeight = 14.0;
      const knobW = 10.0;
      const knobH = 18.0;

      return SizedBox(
        height: knobH + 2,
        child: Stack(
          clipBehavior: Clip.none,
          alignment: Alignment.centerLeft,
          children: [
            // Track
            Positioned(
              top: (knobH - barHeight) / 2,
              left: 0,
              child: Container(
                height: barHeight,
                width: barWidth,
                decoration: BoxDecoration(
                  color: isDark
                      ? AppTheme.darkGreySeparator
                      : AppTheme.lightDividerColor,
                  borderRadius: BorderRadius.circular(barHeight / 2),
                ),
              ),
            ),
            // Fill
            if (progressWidth > 0)
              Positioned(
                top: (knobH - barHeight) / 2,
                left: 0,
                child: Container(
                  height: barHeight,
                  width: progressWidth,
                  decoration: BoxDecoration(
                    gradient: LinearGradient(
                      colors: isOverReference
                          ? [
                              _statusErrorColor(isDark)
                                  .withValues(alpha: 0.8),
                              _statusErrorColor(isDark),
                            ]
                          : const [AppTheme.darkGold, AppTheme.goldColor],
                    ),
                    borderRadius: BorderRadius.only(
                      topLeft: Radius.circular(barHeight / 2),
                      bottomLeft: Radius.circular(barHeight / 2),
                      topRight: clampedProgress >= 1.0
                          ? Radius.circular(barHeight / 2)
                          : Radius.zero,
                      bottomRight: clampedProgress >= 1.0
                          ? Radius.circular(barHeight / 2)
                          : Radius.zero,
                    ),
                    boxShadow: [
                      BoxShadow(
                        color: barColor.withValues(alpha: 0.4),
                        blurRadius: 6,
                        offset: const Offset(0, 2),
                      ),
                    ],
                  ),
                ),
              ),
            // Knob indicator
            if (clampedProgress > 0.03 && clampedProgress < 0.97)
              Positioned(
                left: progressWidth - knobW / 2,
                top: 0,
                child: Container(
                  width: knobW,
                  height: knobH,
                  decoration: BoxDecoration(
                    color: isDark ? const Color(0xFF2A2A2A) : Colors.white,
                    borderRadius: BorderRadius.circular(5),
                    border: Border.all(color: barColor, width: 2.5),
                    boxShadow: [
                      BoxShadow(
                        color: barColor.withValues(alpha: 0.5),
                        blurRadius: 5,
                        spreadRadius: 0.5,
                      ),
                    ],
                  ),
                ),
              ),
            // Completion checkmark
            if (clampedProgress >= 0.97)
              Positioned(
                right: 0,
                top: (knobH - barHeight) / 2,
                child: Container(
                  width: barHeight,
                  height: barHeight,
                  decoration: BoxDecoration(
                    color: barColor,
                    shape: BoxShape.circle,
                  ),
                  child: Icon(
                    LucideIcons.check,
                    color: Colors.white,
                    size: 9.sp,
                  ),
                ),
              ),
          ],
        ),
      );
    },
  );
}

